import React, { useEffect, useState } from 'react';
import axios from 'axios';

const STORE_ID = '36265ff8-1750-4f6f-8ec7-4c6925e77901';
const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;

function Sales() {
  const [products, setProducts] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState('');
  const [quantity, setQuantity] = useState('');
  const [message, setMessage] = useState('');

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const res = await axios.get(`${BACKEND_URL}/products/${STORE_ID}`);
      setProducts(res.data.products);
    } catch (err) {
      console.error('Error fetching products:', err);
    }
  };

  const handleSale = async (e) => {
    e.preventDefault();
    const product = products.find(p => p.id === selectedProduct);
    if (!product) return;

    try {
      await axios.post(`${BACKEND_URL}/sales`, {
        store_id: STORE_ID,
        items: [
          {
            product_id: selectedProduct,
            quantity: parseInt(quantity),
            unit_price: product.price
          }
        ]
      });
      setMessage(`Sale recorded! ${quantity} x ${product.name} sold for KSh ${product.price * quantity}`);
      setSelectedProduct('');
      setQuantity('');
      fetchProducts();
    } catch (err) {
      setMessage('Error recording sale. Please try again.');
    }
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <h1>Record a Sale</h1>

      {message && (
        <div style={{ background: '#d4edda', padding: '10px', borderRadius: '8px', marginBottom: '20px' }}>
          {message}
        </div>
      )}

      <form onSubmit={handleSale} style={{ maxWidth: '400px' }}>
        <div style={{ marginBottom: '15px' }}>
          <label>Select Product</label><br />
          <select value={selectedProduct} onChange={e => setSelectedProduct(e.target.value)} required
            style={{ width: '100%', padding: '8px', marginTop: '5px' }}>
            <option value="">-- Select a product --</option>
            {products.map(p => (
              <option key={p.id} value={p.id}>
                {p.name} (Stock: {p.quantity}) — KSh {p.price}
              </option>
            ))}
          </select>
        </div>
        <div style={{ marginBottom: '15px' }}>
          <label>Quantity Sold</label><br />
          <input type="number" value={quantity} onChange={e => setQuantity(e.target.value)} required
            style={{ width: '100%', padding: '8px', marginTop: '5px' }} />
        </div>
        <button type="submit"
          style={{ background: '#007bff', color: 'white', padding: '10px 20px', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
          Record Sale
        </button>
      </form>

      <h2 style={{ marginTop: '40px' }}>Current Stock</h2>
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr style={{ background: '#f0f0f0' }}>
            <th style={{ padding: '10px', textAlign: 'left' }}>Name</th>
            <th style={{ padding: '10px', textAlign: 'left' }}>Quantity</th>
            <th style={{ padding: '10px', textAlign: 'left' }}>Price (KSh)</th>
          </tr>
        </thead>
        <tbody>
          {products.map(p => (
            <tr key={p.id} style={{ borderBottom: '1px solid #ddd' }}>
              <td style={{ padding: '10px' }}>{p.name}</td>
              <td style={{ padding: '10px', color: p.quantity <= p.low_stock_threshold ? 'red' : 'green' }}>
                {p.quantity}
              </td>
              <td style={{ padding: '10px' }}>KSh {p.price}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Sales;
